import React from "react";
import "./About.css";

export default function About() {
  return (
    <section id="about">
      <h2>About Me</h2>
      <p>
        I am a highly motivated 3rd year Computer Science student at Ben-Gurion
        University of the Negev, <br />
        currently in my last semester. Passionate about technology since
        childhood, I focus on programming and problem-solving. Eager to learn
        new technologies and deliver high-quality solutions, I work well both
        independently and collaboratively, valuing open communication and
        knowledge sharing. I seek opportunities to contribute my technical
        skills, adaptability, and strong work ethic to a dynamic organization.
      </p>
    </section>
  );
}
